var COURSE_PL_ES = [{day: 1, title: `Pierwsze powitania`, title_native: `Primeros saludos`, focus: `Dziś uczysz się najważniejszych powitań i pożegnań, których użyjesz od razu po przylocie do Madrytu, Meksyku lub Buenos Aires. Skup się na krótkich, uprzejmych zwrotach, które otwierają każdą rozmowę.`, vocab: [{es: `hola`, pl: `cześć`, ipa: `/ola/`},{es: `buenos días`, pl: `dzień dobry`, ipa: `/błenos dijas/`},{es: `buenas tardes`, pl: `dobry wieczór, dobre popołudnie`, ipa: `/błenas tardes/`},{es: `buenas noches`, pl: `dobry wieczór, dobranoc`, ipa: `/błenas noczes/`},{es: `adiós`, pl: `do widzenia`, ipa: `/adjos/`},{es: `gracias`, pl: `dziękuję`, ipa: `/grasjas/`},{es: `por favor`, pl: `proszę`, ipa: `/por fabor/`},{es: `sí`, pl: `tak`, ipa: `/si/`},{es: `no`, pl: `nie`, ipa: `/no/`},{es: `perdón`, pl: `przepraszam`, ipa: `/perdon/`}], phrases: [{es: `Hola, buenos días.`, pl: `Cześć, dzień dobry.`, ipa: `/ola błenos dijas/`},{es: `Gracias.`, pl: `Dziękuję.`, ipa: `/grasjas/`},{es: `Por favor.`, pl: `Proszę.`, ipa: `/por fabor/`},{es: `Perdón.`, pl: `Przepraszam.`, ipa: `/perdon/`},{es: `Adiós, buenas noches.`, pl: `Do widzenia, dobranoc.`, ipa: `/adjos błenas noczes/`}], grammar: `W języku hiszpańskim powitanie często zależy od pory dnia. Buenos días używa się rano, buenas tardes po południu, a buenas noches wieczorem i przy pożegnaniu przed snem. W podróży warto dodać por favor i gracias prawie w każdej krótkiej rozmowie, bo brzmi to naturalnie i uprzejmie.`, practice: [`Powiedz po hiszpańsku „dzień dobry” i „dziękuję”.`,`Połącz powitanie z prośbą: „Dzień dobry, proszę”.`,`Wyobraź sobie, że wchodzisz do małej kawiarni w Madrycie i przywitaj się z obsługą.`,`Przećwicz różnicę między buenas tardes i buenas noches.`,`Napisz krótką wymianę: cześć, dziękuję, do widzenia.`]},{day: 2, title: `Przedstawianie się`, title_native: `Presentarse`, focus: `Dziś nauczysz się mówić, jak masz na imię i skąd jesteś. To przyda się w hostelu w Barcelonie, na wycieczce w Meksyku lub podczas rozmowy z lokalnym mieszkańcem.`, vocab: [{es: `me llamo`, pl: `nazywam się`, ipa: `/me jamo/`},{es: `nombre`, pl: `imię`, ipa: `/nombre/`},{es: `soy`, pl: `jestem`, ipa: `/soj/`},{es: `de`, pl: `z`, ipa: `/de/`},{es: `Polonia`, pl: `Polska`, ipa: `/polonja/`},{es: `amigo`, pl: `przyjaciel`, ipa: `/amigo/`},{es: `amiga`, pl: `przyjaciółka`, ipa: `/amiga/`},{es: `encantado`, pl: `miło mi, forma męska`, ipa: `/enkantado/`},{es: `encantada`, pl: `miło mi, forma żeńska`, ipa: `/enkantada/`},{es: `también`, pl: `też, również`, ipa: `/tambjen/`}], phrases: [{es: `Me llamo Anna.`, pl: `Nazywam się Anna.`, ipa: `/me jamo anna/`},{es: `Soy de Polonia.`, pl: `Jestem z Polski.`, ipa: `/soj de polonja/`},{es: `¿Cómo te llamas?`, pl: `Jak się nazywasz?`, ipa: `/komo te jamas/`},{es: `Encantado.`, pl: `Miło mi.`, ipa: `/enkantado/`},{es: `Yo también.`, pl: `Ja też.`, ipa: `/jo tambjen/`}], grammar: `Hiszpańskie ll w wielu krajach brzmi podobnie do polskiego „j”, dlatego me llamo czyta się mniej więcej „me jamo”. Soy znaczy „jestem” w sensie tożsamości lub pochodzenia. Gdy mówisz „miło mi”, użyj encantado, jeśli jesteś mężczyzną, i encantada, jeśli jesteś kobietą.`, practice: [`Powiedz swoje imię po hiszpańsku, używając me llamo.`,`Powiedz, że jesteś z Polski.`,`Zapytaj drugą osobę, jak się nazywa.`,`Przećwicz odpowiedź: Encantado lub Encantada.`,`Ułóż dialog dwóch osób poznających się w hostelu.`]},{day: 3, title: `Proste pytania i odpowiedzi`, title_native: `Preguntas y respuestas simples`, focus: `Dziś ćwiczysz najprostsze pytania, które pomogą ci rozpocząć rozmowę w Sewilli, Limie lub Walencji. Nauczysz się też odpowiadać krótko i naturalnie.`, vocab: [{es: `qué`, pl: `co`, ipa: `/ke/`},{es: `quién`, pl: `kto`, ipa: `/kjen/`},{es: `dónde`, pl: `gdzie`, ipa: `/donde/`},{es: `cuándo`, pl: `kiedy`, ipa: `/kłando/`},{es: `cómo`, pl: `jak`, ipa: `/komo/`},{es: `cuánto`, pl: `ile`, ipa: `/kłanto/`},{es: `aquí`, pl: `tutaj`, ipa: `/aki/`},{es: `allí`, pl: `tam`, ipa: `/aji/`},{es: `bien`, pl: `dobrze`, ipa: `/bjen/`},{es: `mal`, pl: `źle`, ipa: `/mal/`}], phrases: [{es: `¿Cómo estás?`, pl: `Jak się masz?`, ipa: `/komo estas/`},{es: `Estoy bien.`, pl: `Mam się dobrze.`, ipa: `/estoj bjen/`},{es: `¿Dónde está?`, pl: `Gdzie to jest?`, ipa: `/donde esta/`},{es: `¿Qué es esto?`, pl: `Co to jest?`, ipa: `/ke es esto/`},{es: `¿Cuánto cuesta?`, pl: `Ile to kosztuje?`, ipa: `/kłanto kłesta/`}], grammar: `W hiszpańskim pytania często mają odwrócony znak zapytania na początku: ¿Cómo estás? W mowie usłyszysz głównie intonację pytającą, ale w piśmie ten znak jest obowiązkowy. Słowa pytające mają akcent graficzny, gdy działają jako pytania: qué, dónde, cómo.`, practice: [`Zapytaj po hiszpańsku „Jak się masz?”.`,`Odpowiedz: „Mam się dobrze”.`,`Zapytaj „Gdzie to jest?”.`,`Zapytaj „Ile to kosztuje?”.`,`Wymyśl trzy krótkie pytania przydatne na lotnisku.`]},{day: 4, title: `Liczby od 0 do 20`, title_native: `Números del cero al veinte`, focus: `Dziś poznasz podstawowe liczby potrzebne przy płaceniu, rezerwacji i podawaniu numeru pokoju. To bardzo praktyczna lekcja dla podróży po Hiszpanii i Ameryce Łacińskiej.`, vocab: [{es: `cero`, pl: `zero`, ipa: `/sero/`},{es: `uno`, pl: `jeden`, ipa: `/uno/`},{es: `dos`, pl: `dwa`, ipa: `/dos/`},{es: `tres`, pl: `trzy`, ipa: `/tres/`},{es: `cuatro`, pl: `cztery`, ipa: `/kłatro/`},{es: `cinco`, pl: `pięć`, ipa: `/sinko/`},{es: `seis`, pl: `sześć`, ipa: `/sejs/`},{es: `siete`, pl: `siedem`, ipa: `/sjete/`},{es: `ocho`, pl: `osiem`, ipa: `/oczo/`},{es: `diez`, pl: `dziesięć`, ipa: `/djes/`}], phrases: [{es: `Uno, por favor.`, pl: `Jeden, proszę.`, ipa: `/uno por fabor/`},{es: `Dos cafés, por favor.`, pl: `Dwie kawy, proszę.`, ipa: `/dos kafes por fabor/`},{es: `Tengo tres maletas.`, pl: `Mam trzy walizki.`, ipa: `/tengo tres maletas/`},{es: `Habitación cinco.`, pl: `Pokój numer pięć.`, ipa: `/abitasion sinko/`},{es: `Son diez euros.`, pl: `To dziesięć euro.`, ipa: `/son djes euros/`}], grammar: `Hiszpańskie liczebniki są niezbędne przy zamawianiu i płaceniu. Uno zmienia się często na un przed rzeczownikiem męskim, na przykład un café. Dos, tres i kolejne liczby nie zmieniają formy ze względu na rodzaj.`, practice: [`Policz po hiszpańsku od 0 do 10.`,`Powiedz „dwie kawy, proszę”.`,`Powiedz „mam trzy walizki”.`,`Zapytaj kolegę o numer pokoju i odpowiedz liczbą.`,`Poćwicz ceny: 5 euro, 8 euro, 10 euro.`]},{day: 5, title: `Uprzejme prośby`, title_native: `Peticiones amables`, focus: `Dziś uczysz się prosić o pomoc w prosty i grzeczny sposób. Przyda się to w hotelu w Granadzie, na dworcu w Madrycie i w restauracji w Quito.`, vocab: [{es: `quiero`, pl: `chcę`, ipa: `/kjero/`},{es: `quisiera`, pl: `chciałbym, chciałabym`, ipa: `/kisjera/`},{es: `necesito`, pl: `potrzebuję`, ipa: `/nesesito/`},{es: `ayuda`, pl: `pomoc`, ipa: `/ajuda/`},{es: `agua`, pl: `woda`, ipa: `/agła/`},{es: `baño`, pl: `łazienka, toaleta`, ipa: `/banio/`},{es: `mesa`, pl: `stół`, ipa: `/mesa/`},{es: `mapa`, pl: `mapa`, ipa: `/mapa/`},{es: `boleto`, pl: `bilet`, ipa: `/boleto/`},{es: `entrada`, pl: `wejście, bilet wstępu`, ipa: `/entrada/`}], phrases: [{es: `Quisiera agua, por favor.`, pl: `Poproszę wodę.`, ipa: `/kisjera agła por fabor/`},{es: `Necesito ayuda.`, pl: `Potrzebuję pomocy.`, ipa: `/nesesito ajuda/`},{es: `¿Dónde está el baño?`, pl: `Gdzie jest toaleta?`, ipa: `/donde esta el banio/`},{es: `Quiero una entrada.`, pl: `Chcę jeden bilet wstępu.`, ipa: `/kjero una entrada/`},{es: `¿Me puede ayudar?`, pl: `Czy może mi pan/pani pomóc?`, ipa: `/me płede ajudar/`}], grammar: `Quiero znaczy „chcę”, ale w wielu sytuacjach brzmi bezpośrednio. Quisiera jest bardziej uprzejme i znaczy „chciałbym/chciałabym”. W podróży najlepiej zaczynać prośby od quisiera albo ¿me puede ayudar?, szczególnie w hotelu, restauracji i informacji turystycznej.`, practice: [`Poproś o wodę w uprzejmy sposób.`,`Zapytaj, gdzie jest toaleta.`,`Powiedz, że potrzebujesz pomocy.`,`Poproś o jeden bilet wstępu.`,`Odegraj krótką scenkę w informacji turystycznej.`]},{day: 6, title: `Na lotnisku`, title_native: `En el aeropuerto`, focus: `Dziś poznasz słowa potrzebne po przylocie na lotnisko w Madrycie, Bogocie lub Meksyku. Nauczysz się pytać o bagaż, wyjście i transport.`, vocab: [{es: `aeropuerto`, pl: `lotnisko`, ipa: `/aeropłerto/`},{es: `vuelo`, pl: `lot`, ipa: `/błelo/`},{es: `pasaporte`, pl: `paszport`, ipa: `/pasaporte/`},{es: `equipaje`, pl: `bagaż`, ipa: `/ekipache/`},{es: `maleta`, pl: `walizka`, ipa: `/maleta/`},{es: `salida`, pl: `wyjście, odlot`, ipa: `/salida/`},{es: `llegada`, pl: `przylot`, ipa: `/jegada/`},{es: `aduana`, pl: `odprawa celna`, ipa: `/adłana/`},{es: `taxi`, pl: `taksówka`, ipa: `/taksi/`},{es: `autobús`, pl: `autobus`, ipa: `/autobus/`}], phrases: [{es: `¿Dónde está el equipaje?`, pl: `Gdzie jest bagaż?`, ipa: `/donde esta el ekipache/`},{es: `Necesito un taxi.`, pl: `Potrzebuję taksówki.`, ipa: `/nesesito un taksi/`},{es: `Aquí está mi pasaporte.`, pl: `Oto mój paszport.`, ipa: `/aki esta mi pasaporte/`},{es: `¿Dónde está la salida?`, pl: `Gdzie jest wyjście?`, ipa: `/donde esta la salida/`},{es: `Mi vuelo llega tarde.`, pl: `Mój lot przylatuje późno.`, ipa: `/mi błelo jega tarde/`}], grammar: `El i la to hiszpańskie odpowiedniki „ten/ta/to”. El używa się zwykle z rzeczownikami męskimi, na przykład el aeropuerto, a la z żeńskimi, na przykład la salida. Nie zawsze rodzaj odpowiada intuicji z polskiego, więc ucz się rzeczowników razem z el albo la.`, practice: [`Zapytaj, gdzie jest bagaż.`,`Powiedz: „Oto mój paszport”.`,`Zapytaj o wyjście z lotniska.`,`Powiedz, że potrzebujesz taksówki.`,`Ułóż dialog przy kontroli paszportowej.`]},{day: 7, title: `Hotel i zakwaterowanie`, title_native: `Hotel y alojamiento`, focus: `Dziś uczysz się meldować w hotelu i pytać o pokój. Lekcja pasuje do sytuacji w hotelu w Barcelonie, Cartagenie lub Buenos Aires.`, vocab: [{es: `hotel`, pl: `hotel`, ipa: `/otel/`},{es: `reserva`, pl: `rezerwacja`, ipa: `/reserba/`},{es: `habitación`, pl: `pokój`, ipa: `/abitasion/`},{es: `llave`, pl: `klucz`, ipa: `/jawe/`},{es: `cama`, pl: `łóżko`, ipa: `/kama/`},{es: `ducha`, pl: `prysznic`, ipa: `/ducza/`},{es: `desayuno`, pl: `śniadanie`, ipa: `/desajuno/`},{es: `recepción`, pl: `recepcja`, ipa: `/resepsjon/`},{es: `noche`, pl: `noc`, ipa: `/nocze/`},{es: `ascensor`, pl: `winda`, ipa: `/asensor/`}], phrases: [{es: `Tengo una reserva.`, pl: `Mam rezerwację.`, ipa: `/tengo una reserba/`},{es: `Quisiera registrarme.`, pl: `Chciałbym/chciałabym się zameldować.`, ipa: `/kisjera rechistrarme/`},{es: `¿Dónde está mi habitación?`, pl: `Gdzie jest mój pokój?`, ipa: `/donde esta mi abitasion/`},{es: `¿El desayuno está incluido?`, pl: `Czy śniadanie jest wliczone?`, ipa: `/el desayuno esta inkluido/`},{es: `Necesito la llave.`, pl: `Potrzebuję klucza.`, ipa: `/nesesito la jawe/`}], grammar: `Tengo znaczy „mam” i jest bardzo użyteczne w hotelu: tengo una reserva, tengo una pregunta, tengo una maleta. W hiszpańskim często używa się rodzajnika una przy rzeczownikach żeńskich, na przykład una reserva i una habitación.`, practice: [`Powiedz, że masz rezerwację.`,`Zapytaj, czy śniadanie jest wliczone.`,`Poproś o klucz do pokoju.`,`Zapytaj, gdzie jest winda.`,`Odegraj meldowanie w hotelu w Barcelonie.`]},{day: 8, title: `Kawiarnia i szybkie zamówienia`, title_native: `Café y pedidos rápidos`, focus: `Dziś zamówisz kawę, wodę i prostą przekąskę. To idealna lekcja na poranek w kawiarni w Madrycie, Maladze lub Meksyku.`, vocab: [{es: `café`, pl: `kawa`, ipa: `/kafe/`},{es: `té`, pl: `herbata`, ipa: `/te/`},{es: `leche`, pl: `mleko`, ipa: `/lecze/`},{es: `azúcar`, pl: `cukier`, ipa: `/asukar/`},{es: `agua mineral`, pl: `woda mineralna`, ipa: `/agła mineral/`},{es: `pan`, pl: `chleb`, ipa: `/pan/`},{es: `tostada`, pl: `tost`, ipa: `/tostada/`},{es: `jugo`, pl: `sok`, ipa: `/chugo/`},{es: `zumo`, pl: `sok, głównie Hiszpania`, ipa: `/sumo/`},{es: `cuenta`, pl: `rachunek`, ipa: `/kłenta/`}], phrases: [{es: `Un café, por favor.`, pl: `Kawę, proszę.`, ipa: `/un kafe por fabor/`},{es: `Con leche, por favor.`, pl: `Z mlekiem, proszę.`, ipa: `/kon lecze por fabor/`},{es: `Sin azúcar.`, pl: `Bez cukru.`, ipa: `/sin asukar/`},{es: `¿Tiene jugo de naranja?`, pl: `Czy macie sok pomarańczowy?`, ipa: `/tjene chugo de naranja/`},{es: `La cuenta, por favor.`, pl: `Rachunek, proszę.`, ipa: `/la kłenta por fabor/`}], grammar: `Con znaczy „z”, a sin znaczy „bez”. To bardzo praktyczne słowa przy jedzeniu i piciu: café con leche, agua sin gas, té con azúcar. W Hiszpanii częściej usłyszysz zumo, a w wielu krajach Ameryki Łacińskiej jugo.`, practice: [`Zamów kawę z mlekiem.`,`Poproś o herbatę bez cukru.`,`Zapytaj o sok pomarańczowy.`,`Poproś o rachunek.`,`Ułóż krótką rozmowę w kawiarni w Maladze.`]},{day: 9, title: `Jedzenie i menu`, title_native: `Comida y menú`, focus: `Dziś nauczysz się czytać proste menu i zamawiać jedzenie w restauracji. Przyda się to w tapas barze w Sewilli albo w restauracji w Limie.`, vocab: [{es: `comida`, pl: `jedzenie`, ipa: `/komida/`},{es: `menú`, pl: `menu`, ipa: `/menu/`},{es: `plato`, pl: `danie, talerz`, ipa: `/plato/`},{es: `sopa`, pl: `zupa`, ipa: `/sopa/`},{es: `ensalada`, pl: `sałatka`, ipa: `/ensalada/`},{es: `pollo`, pl: `kurczak`, ipa: `/pojo/`},{es: `pescado`, pl: `ryba`, ipa: `/peskado/`},{es: `carne`, pl: `mięso`, ipa: `/karne/`},{es: `arroz`, pl: `ryż`, ipa: `/arros/`},{es: `postre`, pl: `deser`, ipa: `/postre/`}], phrases: [{es: `Quisiera el menú.`, pl: `Poproszę menu.`, ipa: `/kisjera el menu/`},{es: `¿Qué recomienda?`, pl: `Co pan/pani poleca?`, ipa: `/ke rekomjenda/`},{es: `Quisiera pollo.`, pl: `Poproszę kurczaka.`, ipa: `/kisjera pojo/`},{es: `No como carne.`, pl: `Nie jem mięsa.`, ipa: `/no komo karne/`},{es: `¿Tiene postre?`, pl: `Czy macie deser?`, ipa: `/tjene postre/`}], grammar: `Como znaczy „jem”, ale też może znaczyć „jak” w innych kontekstach bez akcentu. No como carne to prosty sposób, żeby powiedzieć o ograniczeniach żywieniowych. W restauracji warto używać quisiera zamiast quiero, bo brzmi grzeczniej.`, practice: [`Poproś o menu.`,`Powiedz, że nie jesz mięsa.`,`Zamów kurczaka albo rybę.`,`Zapytaj, co kelner poleca.`,`Wymyśl zamówienie z daniem głównym i deserem.`]},{day: 10, title: `Preferencje i alergie`, title_native: `Preferencias y alergias`, focus: `Dziś nauczysz się mówić, co możesz, a czego nie możesz jeść. To ważne w restauracjach w Meksyku, Hiszpanii i Peru, gdzie składniki mogą się różnić regionalnie.`, vocab: [{es: `alergia`, pl: `alergia`, ipa: `/alerchia/`},{es: `alérgico`, pl: `uczulony, forma męska`, ipa: `/alerchiko/`},{es: `alérgica`, pl: `uczulona, forma żeńska`, ipa: `/alerchika/`},{es: `mariscos`, pl: `owoce morza`, ipa: `/mariskos/`},{es: `nueces`, pl: `orzechy`, ipa: `/nłeses/`},{es: `leche`, pl: `mleko`, ipa: `/lecze/`},{es: `huevo`, pl: `jajko`, ipa: `/łewo/`},{es: `gluten`, pl: `gluten`, ipa: `/gluten/`},{es: `picante`, pl: `ostre`, ipa: `/pikante/`},{es: `vegetariano`, pl: `wegetariański, wegetarianin`, ipa: `/bechetarjano/`}], phrases: [{es: `Soy alérgico a las nueces.`, pl: `Jestem uczulony na orzechy.`, ipa: `/soj alerchiko a las nłeses/`},{es: `Soy alérgica al gluten.`, pl: `Jestem uczulona na gluten.`, ipa: `/soj alerchika al gluten/`},{es: `¿Es picante?`, pl: `Czy to jest ostre?`, ipa: `/es pikante/`},{es: `No puedo comer mariscos.`, pl: `Nie mogę jeść owoców morza.`, ipa: `/no płedo komer mariskos/`},{es: `Soy vegetariano.`, pl: `Jestem wegetarianinem.`, ipa: `/soj bechetarjano/`}], grammar: `Soy opisuje trwałą cechę lub tożsamość, dlatego mówimy soy vegetariano albo soy alérgico. No puedo znaczy „nie mogę” i jest bardzo ważne przy ograniczeniach: no puedo comer gluten. Pamiętaj, że przymiotniki często zmieniają końcówkę: alérgico dla mężczyzny, alérgica dla kobiety.`, practice: [`Powiedz, że jesteś uczulony lub uczulona na orzechy.`,`Zapytaj, czy danie jest ostre.`,`Powiedz, że nie możesz jeść owoców morza.`,`Powiedz, że jesteś wegetarianinem lub wegetarianką.`,`Ułóż rozmowę z kelnerem o alergii.`]},{day: 11, title: `Pytanie o drogę`, title_native: `Pedir direcciones`, focus: `Dziś nauczysz się pytać o drogę w mieście, na przykład w Barcelonie, Walencji lub Mexico City. Skupisz się na prostych kierunkach i miejscach w centrum.`, vocab: [{es: `calle`, pl: `ulica`, ipa: `/kaje/`},{es: `plaza`, pl: `plac`, ipa: `/plasa/`},{es: `derecha`, pl: `prawo`, ipa: `/derecza/`},{es: `izquierda`, pl: `lewo`, ipa: `/iskjerda/`},{es: `recto`, pl: `prosto`, ipa: `/rekto/`},{es: `cerca`, pl: `blisko`, ipa: `/serka/`},{es: `lejos`, pl: `daleko`, ipa: `/lechos/`},{es: `centro`, pl: `centrum`, ipa: `/sentro/`},{es: `estación`, pl: `stacja, dworzec`, ipa: `/estasion/`},{es: `museo`, pl: `muzeum`, ipa: `/museo/`}], phrases: [{es: `¿Dónde está la estación?`, pl: `Gdzie jest stacja?`, ipa: `/donde esta la estasion/`},{es: `Siga recto.`, pl: `Proszę iść prosto.`, ipa: `/siga rekto/`},{es: `Gire a la derecha.`, pl: `Proszę skręcić w prawo.`, ipa: `/chire a la derecza/`},{es: `Gire a la izquierda.`, pl: `Proszę skręcić w lewo.`, ipa: `/chire a la iskjerda/`},{es: `¿Está cerca?`, pl: `Czy to jest blisko?`, ipa: `/esta serka/`}], grammar: `Está używa się do lokalizacji: ¿Dónde está la estación? i Está cerca. To różni się od soy, które opisuje tożsamość. Przy kierunkach usłyszysz często siga, gire i luego, czyli „proszę iść”, „proszę skręcić” i „potem”.`, practice: [`Zapytaj, gdzie jest stacja.`,`Powiedz „proszę iść prosto”.`,`Powiedz „proszę skręcić w lewo”.`,`Zapytaj, czy muzeum jest blisko.`,`Narysuj prostą mapę i opisz trasę po hiszpańsku.`]},{day: 12, title: `Transport miejski`, title_native: `Transporte urbano`, focus: `Dziś ćwiczysz język potrzebny w metrze, autobusie i tramwaju. To bardzo przydatne w Madrycie, Santiago de Chile, Buenos Aires i Meksyku.`, vocab: [{es: `metro`, pl: `metro`, ipa: `/metro/`},{es: `tren`, pl: `pociąg`, ipa: `/tren/`},{es: `autobús`, pl: `autobus`, ipa: `/autobus/`},{es: `tranvía`, pl: `tramwaj`, ipa: `/tranbija/`},{es: `billete`, pl: `bilet, Hiszpania`, ipa: `/bijete/`},{es: `boleto`, pl: `bilet, Ameryka Łacińska`, ipa: `/boleto/`},{es: `tarjeta`, pl: `karta`, ipa: `/tarcheta/`},{es: `parada`, pl: `przystanek`, ipa: `/parada/`},{es: `línea`, pl: `linia`, ipa: `/linea/`},{es: `destino`, pl: `cel podróży`, ipa: `/destino/`}], phrases: [{es: `Quisiera un billete.`, pl: `Poproszę bilet.`, ipa: `/kisjera un bijete/`},{es: `¿A qué hora sale el tren?`, pl: `O której odjeżdża pociąg?`, ipa: `/a ke ora sale el tren/`},{es: `¿Dónde está la parada?`, pl: `Gdzie jest przystanek?`, ipa: `/donde esta la parada/`},{es: `Necesito una tarjeta.`, pl: `Potrzebuję karty.`, ipa: `/nesesito una tarcheta/`},{es: `¿Esta línea va al centro?`, pl: `Czy ta linia jedzie do centrum?`, ipa: `/esta linea ba al sentro/`}], grammar: `Va znaczy „idzie” lub „jedzie” w odniesieniu do transportu. ¿Va al centro? to bardzo praktyczne pytanie, gdy nie masz pewności, czy wsiadasz do właściwego autobusu lub metra. W Hiszpanii częściej usłyszysz billete, a w wielu krajach Ameryki Łacińskiej boleto.`, practice: [`Poproś o bilet na metro.`,`Zapytaj, gdzie jest przystanek.`,`Zapytaj, czy ta linia jedzie do centrum.`,`Powiedz, że potrzebujesz karty miejskiej.`,`Ułóż rozmowę przy kasie biletowej.`]},{day: 13, title: `Taksówka i aplikacje przejazdowe`, title_native: `Taxi y aplicaciones de transporte`, focus: `Dziś nauczysz się podawać adres, pytać o cenę i potwierdzać trasę w taksówce. Scenariusz pasuje do miasta Meksyk, Bogoty lub Madrytu.`, vocab: [{es: `taxi`, pl: `taksówka`, ipa: `/taksi/`},{es: `conductor`, pl: `kierowca`, ipa: `/konduktor/`},{es: `dirección`, pl: `adres`, ipa: `/direksjon/`},{es: `hotel`, pl: `hotel`, ipa: `/otel/`},{es: `precio`, pl: `cena`, ipa: `/presjo/`},{es: `ruta`, pl: `trasa`, ipa: `/ruta/`},{es: `rápido`, pl: `szybko`, ipa: `/rapido/`},{es: `lento`, pl: `wolno`, ipa: `/lento/`},{es: `tráfico`, pl: `ruch uliczny`, ipa: `/trafiko/`},{es: `aquí`, pl: `tutaj`, ipa: `/aki/`}], phrases: [{es: `A esta dirección, por favor.`, pl: `Pod ten adres, proszę.`, ipa: `/a esta direksjon por fabor/`},{es: `¿Cuánto cuesta más o menos?`, pl: `Ile to mniej więcej kosztuje?`, ipa: `/kłanto kłesta mas o menos/`},{es: `¿Puede ir al hotel?`, pl: `Czy może pan/pani jechać do hotelu?`, ipa: `/płede ir al otel/`},{es: `Hay mucho tráfico.`, pl: `Jest duży ruch.`, ipa: `/aj muczo trafiko/`},{es: `Aquí está bien.`, pl: `Tutaj jest dobrze.`, ipa: `/aki esta bjen/`}], grammar: `Hay znaczy „jest/są” w sensie istnienia czegoś: hay tráfico, hay una parada, hay un problema. To jedno z najpraktyczniejszych słów w podróży. Gdy chcesz wysiąść, możesz powiedzieć aquí está bien, czyli „tutaj będzie dobrze”.`, practice: [`Powiedz kierowcy: „Pod ten adres, proszę”.`,`Zapytaj o przybliżoną cenę.`,`Powiedz, że jest duży ruch.`,`Powiedz, że tutaj jest dobrze.`,`Ułóż rozmowę z kierowcą taksówki.`]},{day: 14, title: `Zakupy i ceny`, title_native: `Compras y precios`, focus: `Dziś uczysz się pytać o ceny, rozmiary i płatność. Przyda się to na targu w Meksyku, w sklepie w Madrycie lub na bazarze w Limie.`, vocab: [{es: `tienda`, pl: `sklep`, ipa: `/tjenda/`},{es: `mercado`, pl: `targ`, ipa: `/merkado/`},{es: `precio`, pl: `cena`, ipa: `/presjo/`},{es: `barato`, pl: `tani`, ipa: `/barato/`},{es: `caro`, pl: `drogi`, ipa: `/karo/`},{es: `grande`, pl: `duży`, ipa: `/grande/`},{es: `pequeño`, pl: `mały`, ipa: `/pekenio/`},{es: `talla`, pl: `rozmiar`, ipa: `/taja/`},{es: `dinero`, pl: `pieniądze`, ipa: `/dinero/`},{es: `tarjeta`, pl: `karta`, ipa: `/tarcheta/`}], phrases: [{es: `¿Cuánto cuesta esto?`, pl: `Ile to kosztuje?`, ipa: `/kłanto kłesta esto/`},{es: `Es muy caro.`, pl: `To jest bardzo drogie.`, ipa: `/es muj karo/`},{es: `¿Tiene una talla más grande?`, pl: `Czy ma pan/pani większy rozmiar?`, ipa: `/tjene una taja mas grande/`},{es: `Pago con tarjeta.`, pl: `Płacę kartą.`, ipa: `/pago kon tarcheta/`},{es: `Solo estoy mirando.`, pl: `Tylko oglądam.`, ipa: `/solo estoj mirando/`}], grammar: `Muy znaczy „bardzo” i stoi przed przymiotnikiem: muy caro, muy barato, muy grande. Más znaczy „bardziej” lub „więcej”, więc una talla más grande to „większy rozmiar”. W sklepach solo estoy mirando jest uprzejmym sposobem, aby powiedzieć, że tylko oglądasz.`, practice: [`Zapytaj o cenę przedmiotu.`,`Powiedz, że coś jest bardzo drogie.`,`Poproś o większy rozmiar.`,`Powiedz, że płacisz kartą.`,`Odegraj scenkę na targu z pamiątkami.`]},{day: 15, title: `Kolory i opisy`, title_native: `Colores y descripciones`, focus: `Dziś nauczysz się opisywać rzeczy podczas zakupów i pytania o produkty. To przyda się, gdy szukasz ubrania, pamiątki lub konkretnego przedmiotu.`, vocab: [{es: `rojo`, pl: `czerwony`, ipa: `/rocho/`},{es: `azul`, pl: `niebieski`, ipa: `/asul/`},{es: `verde`, pl: `zielony`, ipa: `/berde/`},{es: `negro`, pl: `czarny`, ipa: `/negro/`},{es: `blanco`, pl: `biały`, ipa: `/blanko/`},{es: `amarillo`, pl: `żółty`, ipa: `/amarijo/`},{es: `bonito`, pl: `ładny`, ipa: `/bonito/`},{es: `nuevo`, pl: `nowy`, ipa: `/nłevo/`},{es: `viejo`, pl: `stary`, ipa: `/bjecho/`},{es: `mejor`, pl: `lepszy`, ipa: `/mechor/`}], phrases: [{es: `Quiero el azul.`, pl: `Chcę ten niebieski.`, ipa: `/kjero el asul/`},{es: `¿Tiene uno negro?`, pl: `Czy ma pan/pani czarny?`, ipa: `/tjene uno negro/`},{es: `Es muy bonito.`, pl: `To jest bardzo ładne.`, ipa: `/es muj bonito/`},{es: `Busco algo pequeño.`, pl: `Szukam czegoś małego.`, ipa: `/busko algo pekenio/`},{es: `¿Cuál es mejor?`, pl: `Który jest lepszy?`, ipa: `/kłal es mejor/`}], grammar: `Przymiotniki w hiszpańskim często stoją po rzeczowniku: una camisa roja, un bolso negro. Kolory zwykle dopasowują się do rodzaju i liczby, choć niektóre, jak azul i verde, mają tę samą formę dla rodzaju męskiego i żeńskiego. W praktyce najpierw naucz się prostych zdań typu quiero el azul.`, practice: [`Powiedz, że chcesz niebieski przedmiot.`,`Zapytaj, czy jest czarna wersja.`,`Opisz pamiątkę jako bardzo ładną.`,`Powiedz, że szukasz czegoś małego.`,`Porównaj dwa produkty pytaniem „Który jest lepszy?”.`]},{day: 16, title: `Dni tygodnia i czas`, title_native: `Días de la semana y tiempo`, focus: `Dziś nauczysz się mówić o dniach tygodnia, godzinach i prostych planach. To przyda się przy rezerwacji wycieczki w Barcelonie albo biletu w Meksyku.`, vocab: [{es: `lunes`, pl: `poniedziałek`, ipa: `/lunes/`},{es: `martes`, pl: `wtorek`, ipa: `/martes/`},{es: `miércoles`, pl: `środa`, ipa: `/mjerkoles/`},{es: `jueves`, pl: `czwartek`, ipa: `/chłebes/`},{es: `viernes`, pl: `piątek`, ipa: `/bjernes/`},{es: `sábado`, pl: `sobota`, ipa: `/sabado/`},{es: `domingo`, pl: `niedziela`, ipa: `/domingo/`},{es: `hoy`, pl: `dziś`, ipa: `/oj/`},{es: `mañana`, pl: `jutro, rano`, ipa: `/maniana/`},{es: `hora`, pl: `godzina`, ipa: `/ora/`}], phrases: [{es: `¿Qué día es hoy?`, pl: `Jaki dziś dzień?`, ipa: `/ke dija es oj/`},{es: `Hoy es lunes.`, pl: `Dziś jest poniedziałek.`, ipa: `/oj es lunes/`},{es: `¿A qué hora?`, pl: `O której godzinie?`, ipa: `/a ke ora/`},{es: `Mañana a las nueve.`, pl: `Jutro o dziewiątej.`, ipa: `/maniana a las nłewe/`},{es: `Tengo una reserva el viernes.`, pl: `Mam rezerwację w piątek.`, ipa: `/tengo una reserba el bjernes/`}], grammar: `Dni tygodnia w hiszpańskim pisze się małą literą. El viernes może znaczyć „w piątek”, a los viernes znaczy „w piątki”. Mañana jest ciekawe, bo może znaczyć zarówno „jutro”, jak i „rano”; kontekst zwykle wyjaśnia sens.`, practice: [`Wymień dni tygodnia po hiszpańsku.`,`Powiedz, jaki dziś dzień.`,`Zapytaj „O której godzinie?”.`,`Powiedz „Jutro o dziewiątej”.`,`Powiedz, że masz rezerwację w piątek.`]},{day: 17, title: `Rezerwacje i plany`, title_native: `Reservas y planes`, focus: `Dziś uczysz się rezerwować stolik, bilet lub wizytę. Scenariusze dotyczą restauracji w Madrycie, muzeum w Meksyku i wycieczki w Limie.`, vocab: [{es: `reserva`, pl: `rezerwacja`, ipa: `/reserba/`},{es: `mesa`, pl: `stolik`, ipa: `/mesa/`},{es: `persona`, pl: `osoba`, ipa: `/persona/`},{es: `disponible`, pl: `dostępny`, ipa: `/disponible/`},{es: `hoy`, pl: `dziś`, ipa: `/oj/`},{es: `mañana`, pl: `jutro`, ipa: `/maniana/`},{es: `tarde`, pl: `późno, popołudnie`, ipa: `/tarde/`},{es: `temprano`, pl: `wcześnie`, ipa: `/temprano/`},{es: `confirmar`, pl: `potwierdzić`, ipa: `/konfirmar/`},{es: `cancelar`, pl: `anulować`, ipa: `/kanselar/`}], phrases: [{es: `Quisiera reservar una mesa.`, pl: `Chciałbym/chciałabym zarezerwować stolik.`, ipa: `/kisjera reserbar una mesa/`},{es: `Para dos personas.`, pl: `Dla dwóch osób.`, ipa: `/para dos personas/`},{es: `¿Hay disponibilidad hoy?`, pl: `Czy są dziś wolne miejsca?`, ipa: `/aj disponobilidad oj/`},{es: `Quisiera confirmar mi reserva.`, pl: `Chciałbym/chciałabym potwierdzić rezerwację.`, ipa: `/kisjera konfirmar mi reserba/`},{es: `Necesito cancelar.`, pl: `Muszę anulować.`, ipa: `/nesesito kanselar/`}], grammar: `Para oznacza „dla” albo „do” w sensie celu: para dos personas, para mañana, para el museo. Przy rezerwacjach bardzo często mówi się para + liczba osób. Możesz powiedzieć quisiera reservar, jeśli chcesz brzmieć uprzejmie i naturalnie.`, practice: [`Zarezerwuj stolik dla dwóch osób.`,`Zapytaj, czy są dziś wolne miejsca.`,`Potwierdź rezerwację.`,`Powiedz, że musisz anulować.`,`Ułóż telefoniczną rozmowę z restauracją.`]},{day: 18, title: `Zwiedzanie miasta`, title_native: `Turismo por la ciudad`, focus: `Dziś poznasz słownictwo związane z atrakcjami, muzeami i spacerami po mieście. Przyda się to w Toledo, Granadzie, Cusco lub Mexico City.`, vocab: [{es: `museo`, pl: `muzeum`, ipa: `/museo/`},{es: `iglesia`, pl: `kościół`, ipa: `/iglesja/`},{es: `castillo`, pl: `zamek`, ipa: `/kastijo/`},{es: `parque`, pl: `park`, ipa: `/parke/`},{es: `monumento`, pl: `pomnik, zabytek`, ipa: `/monumento/`},{es: `entrada`, pl: `bilet wstępu, wejście`, ipa: `/entrada/`},{es: `guía`, pl: `przewodnik`, ipa: `/gija/`},{es: `tour`, pl: `wycieczka`, ipa: `/tur/`},{es: `foto`, pl: `zdjęcie`, ipa: `/foto/`},{es: `mapa`, pl: `mapa`, ipa: `/mapa/`}], phrases: [{es: `Quisiera una entrada.`, pl: `Poproszę bilet wstępu.`, ipa: `/kisjera una entrada/`},{es: `¿Puedo tomar fotos?`, pl: `Czy mogę robić zdjęcia?`, ipa: `/płedo tomar fotos/`},{es: `¿A qué hora abre?`, pl: `O której otwiera?`, ipa: `/a ke ora abre/`},{es: `¿A qué hora cierra?`, pl: `O której zamyka?`, ipa: `/a ke ora sjera/`},{es: `Busco un tour en español.`, pl: `Szukam wycieczki po hiszpańsku.`, ipa: `/busko un tur en espaniol/`}], grammar: `Puedo znaczy „mogę” i jest bardzo przydatne w miejscach publicznych: ¿Puedo tomar fotos? ¿Puedo entrar? ¿Puedo pagar con tarjeta? Czasowniki abre i cierra oznaczają „otwiera” i „zamyka”, gdy mówimy o godzinach działania miejsc.`, practice: [`Poproś o bilet do muzeum.`,`Zapytaj, czy można robić zdjęcia.`,`Zapytaj, o której otwiera muzeum.`,`Zapytaj, o której zamyka zamek.`,`Powiedz, że szukasz wycieczki po hiszpańsku.`]},{day: 19, title: `Pogoda i ubrania`, title_native: `Clima y ropa`, focus: `Dziś uczysz się mówić o pogodzie i ubraniach. To praktyczne, gdy planujesz dzień w górach Peru, spacer po Madrycie lub plażę w Walencji.`, vocab: [{es: `clima`, pl: `klimat, pogoda`, ipa: `/klima/`},{es: `tiempo`, pl: `pogoda, czas`, ipa: `/tjempo/`},{es: `sol`, pl: `słońce`, ipa: `/sol/`},{es: `lluvia`, pl: `deszcz`, ipa: `/jubja/`},{es: `frío`, pl: `zimno`, ipa: `/frijo/`},{es: `calor`, pl: `gorąco`, ipa: `/kalor/`},{es: `viento`, pl: `wiatr`, ipa: `/bjento/`},{es: `chaqueta`, pl: `kurtka`, ipa: `/czaketa/`},{es: `zapatos`, pl: `buty`, ipa: `/sapatos/`},{es: `sombrero`, pl: `kapelusz`, ipa: `/sombrero/`}], phrases: [{es: `Hace frío.`, pl: `Jest zimno.`, ipa: `/ase frijo/`},{es: `Hace calor.`, pl: `Jest gorąco.`, ipa: `/ase kalor/`},{es: `Está lloviendo.`, pl: `Pada deszcz.`, ipa: `/esta jobjendo/`},{es: `Necesito una chaqueta.`, pl: `Potrzebuję kurtki.`, ipa: `/nesesito una czaketa/`},{es: `¿Va a llover?`, pl: `Czy będzie padać?`, ipa: `/ba a jober/`}], grammar: `W hiszpańskim mówi się hace frío i hace calor, dosłownie „robi zimno/gorąco”. Dla deszczu używa się está lloviendo albo va a llover, czyli „pada” i „będzie padać”. W podróży te zwroty pomagają planować ubranie i transport.`, practice: [`Powiedz, że jest zimno.`,`Powiedz, że jest gorąco.`,`Powiedz, że pada deszcz.`,`Zapytaj, czy będzie padać.`,`Powiedz, że potrzebujesz kurtki.`]},{day: 20, title: `Apteka i zdrowie`, title_native: `Farmacia y salud`, focus: `Dziś nauczysz się wyjaśniać proste problemy zdrowotne w aptece. To ważne podczas podróży po Hiszpanii, Meksyku, Kolumbii lub Argentynie.`, vocab: [{es: `farmacia`, pl: `apteka`, ipa: `/farmasja/`},{es: `medicina`, pl: `lekarstwo`, ipa: `/medisina/`},{es: `dolor`, pl: `ból`, ipa: `/dolor/`},{es: `cabeza`, pl: `głowa`, ipa: `/kabesa/`},{es: `estómago`, pl: `żołądek`, ipa: `/estomago/`},{es: `fiebre`, pl: `gorączka`, ipa: `/fjebre/`},{es: `tos`, pl: `kaszel`, ipa: `/tos/`},{es: `resfriado`, pl: `przeziębienie`, ipa: `/resfriado/`},{es: `doctor`, pl: `lekarz`, ipa: `/doktor/`},{es: `hospital`, pl: `szpital`, ipa: `/ospital/`}], phrases: [{es: `Me duele la cabeza.`, pl: `Boli mnie głowa.`, ipa: `/me dłełe la kabesa/`},{es: `Me duele el estómago.`, pl: `Boli mnie żołądek.`, ipa: `/me dłełe el estomago/`},{es: `Tengo fiebre.`, pl: `Mam gorączkę.`, ipa: `/tengo fjebre/`},{es: `Necesito medicina.`, pl: `Potrzebuję lekarstwa.`, ipa: `/nesesito medisina/`},{es: `¿Hay una farmacia cerca?`, pl: `Czy jest apteka w pobliżu?`, ipa: `/aj una farmasja serka/`}], grammar: `Me duele znaczy „boli mnie” i łączy się z częścią ciała: me duele la cabeza, me duele el estómago. Gdy mówisz o gorączce, kaszlu lub przeziębieniu, użyj tengo: tengo fiebre, tengo tos, tengo un resfriado. To proste struktury, które szybko pomagają w aptece.`, practice: [`Powiedz, że boli cię głowa.`,`Powiedz, że masz gorączkę.`,`Zapytaj, czy jest apteka w pobliżu.`,`Powiedz, że potrzebujesz lekarstwa.`,`Odegraj rozmowę z farmaceutą.`]},{day: 21, title: `Problemy i awarie`, title_native: `Problemas y emergencias`, focus: `Dziś nauczysz się mówić o problemach, zgubionych rzeczach i nagłych sytuacjach. To przyda się w hotelu, na dworcu i w centrum miasta.`, vocab: [{es: `problema`, pl: `problem`, ipa: `/problema/`},{es: `emergencia`, pl: `nagły wypadek`, ipa: `/emerchensja/`},{es: `policía`, pl: `policja`, ipa: `/polisija/`},{es: `perdido`, pl: `zgubiony`, ipa: `/perdido/`},{es: `teléfono`, pl: `telefon`, ipa: `/telefono/`},{es: `cartera`, pl: `portfel`, ipa: `/kartera/`},{es: `pasaporte`, pl: `paszport`, ipa: `/pasaporte/`},{es: `ayuda`, pl: `pomoc`, ipa: `/ajuda/`},{es: `robo`, pl: `kradzież`, ipa: `/robo/`},{es: `seguro`, pl: `bezpieczny, ubezpieczenie`, ipa: `/seguro/`}], phrases: [{es: `Tengo un problema.`, pl: `Mam problem.`, ipa: `/tengo un problema/`},{es: `Necesito ayuda urgente.`, pl: `Potrzebuję pilnej pomocy.`, ipa: `/nesesito ajuda urchente/`},{es: `He perdido mi pasaporte.`, pl: `Zgubiłem/Zgubiłam paszport.`, ipa: `/e perdido mi pasaporte/`},{es: `¿Dónde está la policía?`, pl: `Gdzie jest policja?`, ipa: `/donde esta la polisija/`},{es: `No encuentro mi teléfono.`, pl: `Nie mogę znaleźć telefonu.`, ipa: `/no enkuentro mi telefono/`}], grammar: `He perdido znaczy „zgubiłem/zgubiłam” i jest bardzo praktyczne przy utracie dokumentów lub przedmiotów. Mi oznacza „mój/moja/moje”, więc mi pasaporte, mi teléfono, mi cartera. W nagłych sytuacjach mów prosto i powtarzaj necesito ayuda.`, practice: [`Powiedz, że masz problem.`,`Powiedz, że potrzebujesz pilnej pomocy.`,`Powiedz, że zgubiłeś lub zgubiłaś paszport.`,`Zapytaj, gdzie jest policja.`,`Powiedz, że nie możesz znaleźć telefonu.`]},{day: 22, title: `Rozmowy towarzyskie`, title_native: `Conversaciones sociales`, focus: `Dziś nauczysz się prowadzić krótką rozmowę z lokalną osobą. Przyda się to w barze w Sewilli, na wycieczce w Peru albo w hostelu w Kolumbii.`, vocab: [{es: `viaje`, pl: `podróż`, ipa: `/bjahe/`},{es: `vacaciones`, pl: `wakacje`, ipa: `/bakasjones/`},{es: `ciudad`, pl: `miasto`, ipa: `/sjudat/`},{es: `país`, pl: `kraj`, ipa: `/pais/`},{es: `familia`, pl: `rodzina`, ipa: `/familja/`},{es: `trabajo`, pl: `praca`, ipa: `/trabacho/`},{es: `música`, pl: `muzyka`, ipa: `/musika/`},{es: `comida`, pl: `jedzenie`, ipa: `/komida/`},{es: `interesante`, pl: `interesujący`, ipa: `/interesante/`},{es: `divertido`, pl: `zabawny, fajny`, ipa: `/dibertido/`}], phrases: [{es: `Estoy de vacaciones.`, pl: `Jestem na wakacjach.`, ipa: `/estoj de bakasjones/`},{es: `Me gusta esta ciudad.`, pl: `Podoba mi się to miasto.`, ipa: `/me gusta esta sjudat/`},{es: `¿De dónde eres?`, pl: `Skąd jesteś?`, ipa: `/de donde eres/`},{es: `¿Qué haces aquí?`, pl: `Co tutaj robisz?`, ipa: `/ke ases aki/`},{es: `La comida es muy buena.`, pl: `Jedzenie jest bardzo dobre.`, ipa: `/la komida es muj błena/`}], grammar: `Me gusta znaczy „podoba mi się” lub „lubię”. W hiszpańskim mówi się dosłownie „mi się podoba”, dlatego me gusta esta ciudad, me gusta la música. Jeśli mówisz o liczbie mnogiej, użyjesz me gustan, na przykład me gustan los tacos.`, practice: [`Powiedz, że jesteś na wakacjach.`,`Powiedz, że podoba ci się to miasto.`,`Zapytaj kogoś, skąd jest.`,`Powiedz, że jedzenie jest bardzo dobre.`,`Ułóż krótką rozmowę w hostelu.`]},{day: 23, title: `Rodzina i ludzie`, title_native: `Familia y personas`, focus: `Dziś poznasz słowa do opisywania ludzi i relacji. To przyda się w rozmowie z gospodarzem, przewodnikiem lub nowo poznaną osobą.`, vocab: [{es: `madre`, pl: `matka`, ipa: `/madre/`},{es: `padre`, pl: `ojciec`, ipa: `/padre/`},{es: `hermano`, pl: `brat`, ipa: `/ermano/`},{es: `hermana`, pl: `siostra`, ipa: `/ermana/`},{es: `hijo`, pl: `syn`, ipa: `/icho/`},{es: `hija`, pl: `córka`, ipa: `/icha/`},{es: `amigo`, pl: `przyjaciel`, ipa: `/amigo/`},{es: `pareja`, pl: `partner, partnerka`, ipa: `/parecha/`},{es: `niño`, pl: `chłopiec, dziecko`, ipa: `/ninio/`},{es: `persona`, pl: `osoba`, ipa: `/persona/`}], phrases: [{es: `Viajo con mi familia.`, pl: `Podróżuję z rodziną.`, ipa: `/bjacho kon mi familja/`},{es: `Este es mi amigo.`, pl: `To jest mój przyjaciel.`, ipa: `/este es mi amigo/`},{es: `Esta es mi hermana.`, pl: `To jest moja siostra.`, ipa: `/esta es mi ermana/`},{es: `Tengo dos hermanos.`, pl: `Mam dwóch braci lub rodzeństwo.`, ipa: `/tengo dos ermanos/`},{es: `¿Viajas solo?`, pl: `Podróżujesz sam?`, ipa: `/bjakas solo/`}], grammar: `Este oznacza „ten” lub „to” dla rzeczownika męskiego, a esta dla żeńskiego. Este es mi amigo, ale esta es mi hermana. Hermanos może oznaczać „bracia” albo ogólnie „rodzeństwo”, jeśli grupa jest mieszana.`, practice: [`Powiedz, że podróżujesz z rodziną.`,`Przedstaw przyjaciela.`,`Przedstaw siostrę.`,`Powiedz, że masz dwoje rodzeństwa.`,`Zapytaj kogoś, czy podróżuje sam.`]},{day: 24, title: `Telefon, internet i technologia`, title_native: `Teléfono, internet y tecnología`, focus: `Dziś uczysz się pytać o Wi-Fi, ładowarkę i kartę SIM. To przyda się w hotelu, kawiarni i sklepie telefonicznym w Hiszpanii lub Ameryce Łacińskiej.`, vocab: [{es: `teléfono`, pl: `telefon`, ipa: `/telefono/`},{es: `internet`, pl: `internet`, ipa: `/internet/`},{es: `wifi`, pl: `Wi-Fi`, ipa: `/łifi/`},{es: `contraseña`, pl: `hasło`, ipa: `/kontrasenia/`},{es: `cargador`, pl: `ładowarka`, ipa: `/kargador/`},{es: `batería`, pl: `bateria`, ipa: `/baterija/`},{es: `tarjeta SIM`, pl: `karta SIM`, ipa: `/tarcheta sim/`},{es: `datos`, pl: `dane`, ipa: `/datos/`},{es: `mensaje`, pl: `wiadomość`, ipa: `/mensache/`},{es: `llamada`, pl: `połączenie`, ipa: `/jamada/`}], phrases: [{es: `¿Cuál es la contraseña del wifi?`, pl: `Jakie jest hasło do Wi-Fi?`, ipa: `/kłal es la kontrasenia del łifi/`},{es: `Necesito un cargador.`, pl: `Potrzebuję ładowarki.`, ipa: `/nesesito un kargador/`},{es: `Mi teléfono no funciona.`, pl: `Mój telefon nie działa.`, ipa: `/mi telefono no funksjona/`},{es: `Quisiera una tarjeta SIM.`, pl: `Poproszę kartę SIM.`, ipa: `/kisjera una tarcheta sim/`},{es: `¿Tiene datos incluidos?`, pl: `Czy ma wliczone dane?`, ipa: `/tjene datos inkluidos/`}], grammar: `No funciona znaczy „nie działa” i możesz użyć tego z telefonem, kartą, klimatyzacją lub kluczem. Mi teléfono no funciona, la tarjeta no funciona, el aire acondicionado no funciona. To bardzo przydatna konstrukcja w hotelach i sklepach.`, practice: [`Zapytaj o hasło do Wi-Fi.`,`Powiedz, że potrzebujesz ładowarki.`,`Powiedz, że telefon nie działa.`,`Poproś o kartę SIM.`,`Zapytaj, czy dane są wliczone.`]},{day: 25, title: `Na plaży i na zewnątrz`, title_native: `En la playa y al aire libre`, focus: `Dziś poznasz słownictwo związane z plażą, spacerem i wypoczynkiem na świeżym powietrzu. To idealne na Walencję, Malagę, Cancún lub Cartagenę.`, vocab: [{es: `playa`, pl: `plaża`, ipa: `/plaja/`},{es: `mar`, pl: `morze`, ipa: `/mar/`},{es: `arena`, pl: `piasek`, ipa: `/arena/`},{es: `sol`, pl: `słońce`, ipa: `/sol/`},{es: `sombra`, pl: `cień`, ipa: `/sombra/`},{es: `toalla`, pl: `ręcznik`, ipa: `/toaja/`},{es: `bañador`, pl: `strój kąpielowy`, ipa: `/baniador/`},{es: `agua`, pl: `woda`, ipa: `/agła/`},{es: `caliente`, pl: `gorący`, ipa: `/kaljente/`},{es: `frío`, pl: `zimny`, ipa: `/frijo/`}], phrases: [{es: `Quiero ir a la playa.`, pl: `Chcę iść na plażę.`, ipa: `/kjero ir a la plaja/`},{es: `¿Dónde puedo comprar una toalla?`, pl: `Gdzie mogę kupić ręcznik?`, ipa: `/donde płedo komprar una toaja/`},{es: `El agua está fría.`, pl: `Woda jest zimna.`, ipa: `/el agła esta frija/`},{es: `Hace mucho sol.`, pl: `Jest bardzo słonecznie.`, ipa: `/ase muczo sol/`},{es: `Necesito sombra.`, pl: `Potrzebuję cienia.`, ipa: `/nesesito sombra/`}], grammar: `Ir a znaczy „iść/jechać do”: ir a la playa, ir al hotel, ir al centro. Al to połączenie a + el, więc mówimy al centro, ale a la playa. Ta konstrukcja przyda ci się codziennie przy planowaniu ruchu po mieście.`, practice: [`Powiedz, że chcesz iść na plażę.`,`Zapytaj, gdzie możesz kupić ręcznik.`,`Powiedz, że woda jest zimna.`,`Powiedz, że jest bardzo słonecznie.`,`Powiedz, że potrzebujesz cienia.`]},{day: 26, title: `Poczta, dokumenty i formalności`, title_native: `Correos, documentos y trámites`, focus: `Dziś uczysz się załatwiać proste sprawy formalne: wysłać pocztówkę, pokazać dokument i zapytać o formularz. Przyda się to podczas dłuższej podróży.`, vocab: [{es: `correo`, pl: `poczta`, ipa: `/koreo/`},{es: `postal`, pl: `pocztówka`, ipa: `/postal/`},{es: `sello`, pl: `znaczek`, ipa: `/sejo/`},{es: `documento`, pl: `dokument`, ipa: `/dokumento/`},{es: `formulario`, pl: `formularz`, ipa: `/formulario/`},{es: `firma`, pl: `podpis`, ipa: `/firma/`},{es: `copia`, pl: `kopia`, ipa: `/kopja/`},{es: `pasaporte`, pl: `paszport`, ipa: `/pasaporte/`},{es: `dirección`, pl: `adres`, ipa: `/direksjon/`},{es: `oficina`, pl: `biuro`, ipa: `/ofisina/`}], phrases: [{es: `Quisiera enviar una postal.`, pl: `Chciałbym/chciałabym wysłać pocztówkę.`, ipa: `/kisjera enbjar una postal/`},{es: `Necesito un sello.`, pl: `Potrzebuję znaczka.`, ipa: `/nesesito un sejo/`},{es: `Aquí está mi documento.`, pl: `Oto mój dokument.`, ipa: `/aki esta mi dokumento/`},{es: `¿Dónde firmo?`, pl: `Gdzie mam podpisać?`, ipa: `/donde firmo/`},{es: `Necesito una copia.`, pl: `Potrzebuję kopii.`, ipa: `/nesesito una kopja/`}], grammar: `Enviar znaczy „wysyłać”, a firmar znaczy „podpisywać”. W sytuacjach formalnych warto mówić spokojnie i używać quisiera oraz necesito. ¿Dónde firmo? jest krótkim i naturalnym pytaniem, gdy ktoś podaje ci formularz.`, practice: [`Powiedz, że chcesz wysłać pocztówkę.`,`Powiedz, że potrzebujesz znaczka.`,`Pokaż dokument po hiszpańsku.`,`Zapytaj, gdzie masz podpisać.`,`Powiedz, że potrzebujesz kopii dokumentu.`]},{day: 27, title: `Mieszkanie na kilka dni`, title_native: `Alojamiento por unos días`, focus: `Dziś uczysz się rozmawiać o wynajętym mieszkaniu, kluczach i podstawowych udogodnieniach. To przyda się w Airbnb, pensjonacie lub apartamencie wakacyjnym.`, vocab: [{es: `apartamento`, pl: `mieszkanie, apartament`, ipa: `/apartamento/`},{es: `casa`, pl: `dom`, ipa: `/kasa/`},{es: `llave`, pl: `klucz`, ipa: `/jawe/`},{es: `puerta`, pl: `drzwi`, ipa: `/płerta/`},{es: `cocina`, pl: `kuchnia`, ipa: `/kosina/`},{es: `baño`, pl: `łazienka`, ipa: `/banio/`},{es: `lavadora`, pl: `pralka`, ipa: `/labadora/`},{es: `aire acondicionado`, pl: `klimatyzacja`, ipa: `/ajre akondisjonado/`},{es: `calefacción`, pl: `ogrzewanie`, ipa: `/kalefaksjon/`},{es: `vecino`, pl: `sąsiad`, ipa: `/besino/`}], phrases: [{es: `¿Dónde están las llaves?`, pl: `Gdzie są klucze?`, ipa: `/donde estan las jawes/`},{es: `El aire acondicionado no funciona.`, pl: `Klimatyzacja nie działa.`, ipa: `/el ajre akondisjonado no funksjona/`},{es: `¿Hay lavadora?`, pl: `Czy jest pralka?`, ipa: `/aj labadora/`},{es: `La puerta no abre.`, pl: `Drzwi się nie otwierają.`, ipa: `/la płerta no abre/`},{es: `Necesito hablar con el dueño.`, pl: `Muszę porozmawiać z właścicielem.`, ipa: `/nesesito ablar kon el dłeńo/`}], grammar: `Están to liczba mnoga od está, używana do lokalizacji wielu rzeczy: ¿Dónde están las llaves? Gdy mówisz o jednej rzeczy, użyj está: ¿Dónde está la llave? Różnica jest ważna, ale w praktyce ludzie i tak zwykle zrozumieją kontekst.`, practice: [`Zapytaj, gdzie są klucze.`,`Powiedz, że klimatyzacja nie działa.`,`Zapytaj, czy jest pralka.`,`Powiedz, że drzwi się nie otwierają.`,`Poproś o rozmowę z właścicielem.`]},{day: 28, title: `Opinie i preferencje`, title_native: `Opiniones y preferencias`, focus: `Dziś nauczysz się mówić, co lubisz, czego nie lubisz i co wolisz. Przyda się to w rozmowach o jedzeniu, planach i miejscach do odwiedzenia.`, vocab: [{es: `me gusta`, pl: `lubię, podoba mi się`, ipa: `/me gusta/`},{es: `no me gusta`, pl: `nie lubię, nie podoba mi się`, ipa: `/no me gusta/`},{es: `prefiero`, pl: `wolę`, ipa: `/prefjero/`},{es: `favorito`, pl: `ulubiony`, ipa: `/faborito/`},{es: `bonito`, pl: `ładny`, ipa: `/bonito/`},{es: `feo`, pl: `brzydki`, ipa: `/feo/`},{es: `tranquilo`, pl: `spokojny`, ipa: `/trankilo/`},{es: `ruidoso`, pl: `hałaśliwy`, ipa: `/rujidoso/`},{es: `interesante`, pl: `interesujący`, ipa: `/interesante/`},{es: `aburrido`, pl: `nudny`, ipa: `/aburido/`}], phrases: [{es: `Me gusta este lugar.`, pl: `Podoba mi się to miejsce.`, ipa: `/me gusta este lugar/`},{es: `No me gusta el ruido.`, pl: `Nie lubię hałasu.`, ipa: `/no me gusta el rujido/`},{es: `Prefiero algo tranquilo.`, pl: `Wolę coś spokojnego.`, ipa: `/prefjero algo trankilo/`},{es: `¿Cuál es tu restaurante favorito?`, pl: `Jaka jest twoja ulubiona restauracja?`, ipa: `/kłal es tu restorante faborito/`},{es: `Es muy interesante.`, pl: `To jest bardzo interesujące.`, ipa: `/es muj interesante/`}], grammar: `Me gusta działa inaczej niż polskie „lubię”, bo rzecz, którą lubisz, jest gramatycznie podmiotem. Dlatego mówimy me gusta este lugar, ale me gustan los museos. Prefiero jest prostsze i działa jak „wolę”: prefiero café, prefiero algo tranquilo.`, practice: [`Powiedz, że podoba ci się to miejsce.`,`Powiedz, że nie lubisz hałasu.`,`Powiedz, że wolisz coś spokojnego.`,`Zapytaj o ulubioną restaurację.`,`Opisz miejsce jako interesujące lub nudne.`]},{day: 29, title: `Łączenie zdań w podróży`, title_native: `Conectar frases durante el viaje`, focus: `Dziś połączysz wcześniejsze słownictwo w dłuższe, naturalne wypowiedzi. Nauczysz się używać „bo”, „ale” i „potem” w praktycznych rozmowach.`, vocab: [{es: `porque`, pl: `ponieważ, bo`, ipa: `/porke/`},{es: `pero`, pl: `ale`, ipa: `/pero/`},{es: `también`, pl: `też`, ipa: `/tambjen/`},{es: `después`, pl: `potem`, ipa: `/despłes/`},{es: `entonces`, pl: `więc, wtedy`, ipa: `/entonses/`},{es: `ahora`, pl: `teraz`, ipa: `/aora/`},{es: `antes`, pl: `wcześniej, przed`, ipa: `/antes/`},{es: `si`, pl: `jeśli`, ipa: `/si/`},{es: `cuando`, pl: `kiedy, gdy`, ipa: `/kłando/`},{es: `con`, pl: `z`, ipa: `/kon/`}], phrases: [{es: `Quiero ir, pero es tarde.`, pl: `Chcę iść, ale jest późno.`, ipa: `/kjero ir pero es tarde/`},{es: `Necesito ayuda porque estoy perdido.`, pl: `Potrzebuję pomocy, bo się zgubiłem.`, ipa: `/nesesito ajuda porke estoj perdido/`},{es: `Después vamos al hotel.`, pl: `Potem idziemy do hotelu.`, ipa: `/despłes bamos al otel/`},{es: `Ahora quiero comer.`, pl: `Teraz chcę jeść.`, ipa: `/aora kjero komer/`},{es: `Si llueve, tomo un taxi.`, pl: `Jeśli pada, biorę taksówkę.`, ipa: `/si juebe tomo un taksi/`}], grammar: `Porque łączy zdanie z powodem: necesito ayuda porque estoy perdido. Pero wprowadza kontrast: quiero ir, pero es tarde. Después pomaga opowiadać plan krok po kroku, co jest bardzo użyteczne podczas umawiania się i organizowania dnia.`, practice: [`Połącz dwa zdania za pomocą porque.`,`Połącz dwa zdania za pomocą pero.`,`Powiedz, co robisz teraz i co robisz potem.`,`Ułóż zdanie z si: „Jeśli pada, biorę taksówkę”.`,`Opisz swój plan dnia w trzech krótkich zdaniach.`]},{day: 30, title: `Pełny dzień podróżnika`, title_native: `Un día completo de viaje`, focus: `Dziś powtarzasz wszystko, co najważniejsze: hotel, jedzenie, transport, zakupy, kierunki i rozmowy. Wyobraź sobie pełny dzień w Madrycie, od śniadania po wieczorny powrót do hotelu.`, vocab: [{es: `día`, pl: `dzień`, ipa: `/dija/`},{es: `mañana`, pl: `rano, jutro`, ipa: `/maniana/`},{es: `tarde`, pl: `popołudnie, późno`, ipa: `/tarde/`},{es: `noche`, pl: `noc, wieczór`, ipa: `/nocze/`},{es: `plan`, pl: `plan`, ipa: `/plan/`},{es: `caminar`, pl: `chodzić, spacerować`, ipa: `/kaminar/`},{es: `comprar`, pl: `kupować`, ipa: `/komprar/`},{es: `comer`, pl: `jeść`, ipa: `/komer/`},{es: `volver`, pl: `wracać`, ipa: `/bolber/`},{es: `descansar`, pl: `odpoczywać`, ipa: `/deskansar/`}], phrases: [{es: `Hoy tengo un plan.`, pl: `Dziś mam plan.`, ipa: `/oj tengo un plan/`},{es: `Por la mañana quiero caminar.`, pl: `Rano chcę spacerować.`, ipa: `/por la maniana kjero kaminar/`},{es: `Después voy a comer.`, pl: `Potem idę jeść.`, ipa: `/despłes boj a komer/`},{es: `Por la tarde quiero comprar algo.`, pl: `Po południu chcę coś kupić.`, ipa: `/por la tarde kjero komprar algo/`},{es: `Por la noche vuelvo al hotel.`, pl: `Wieczorem wracam do hotelu.`, ipa: `/por la nocze bwelbo al otel/`}], grammar: `Voy a + bezokolicznik oznacza bliską przyszłość: voy a comer, voy a caminar, voy a comprar. To prosty sposób mówienia o planach bez nauki pełnego czasu przyszłego. Por la mañana, por la tarde i por la noche pomagają uporządkować cały dzień.`, practice: [`Powiedz, że dziś masz plan.`,`Opisz, co chcesz robić rano.`,`Powiedz, że potem idziesz jeść.`,`Powiedz, że po południu chcesz coś kupić.`,`Opisz cały dzień podróżnika w pięciu zdaniach.`]}];

var CONVERSATIONS_PL_ES = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w małej kawiarni w Madrycie rano po przyjeździe. Chcesz zamówić kawę z mlekiem, tost i zapytać o rachunek.`, lines: [{who: `them`, es: `Buenos días, ¿qué desea?`, pl: `Dzień dobry, czego pan/pani sobie życzy?`},{who: `you`, es: `Buenos días, quisiera un café con leche, por favor.`, pl: `Dzień dobry, poproszę kawę z mlekiem.`},{who: `them`, es: `Claro, ¿algo más?`, pl: `Oczywiście, coś jeszcze?`},{who: `you`, es: `Sí, una tostada, por favor.`, pl: `Tak, tost, proszę.`},{who: `them`, es: `¿Con tomate o con mantequilla?`, pl: `Z pomidorem czy z masłem?`},{who: `you`, es: `Con tomate, por favor.`, pl: `Z pomidorem, proszę.`},{who: `them`, es: `Muy bien, ahora se lo traigo.`, pl: `Bardzo dobrze, zaraz przyniosę.`},{who: `you`, es: `Gracias.`, pl: `Dziękuję.`},{who: `them`, es: `Aquí tiene su café y su tostada.`, pl: `Oto pana/pani kawa i tost.`},{who: `you`, es: `Perfecto, gracias. La cuenta, por favor.`, pl: `Świetnie, dziękuję. Rachunek, proszę.`},{who: `them`, es: `Son seis euros.`, pl: `To sześć euro.`},{who: `you`, es: `Pago con tarjeta.`, pl: `Płacę kartą.`}]},{id: 2, title: `Meldowanie w hotelu`, scene: `Przyjeżdżasz do hotelu w Barcelonie po długiej podróży. Masz rezerwację i chcesz zapytać o śniadanie oraz windę.`, lines: [{who: `them`, es: `Buenas tardes, bienvenido al hotel.`, pl: `Dobry wieczór, witamy w hotelu.`},{who: `you`, es: `Buenas tardes, tengo una reserva.`, pl: `Dobry wieczór, mam rezerwację.`},{who: `them`, es: `¿A nombre de quién?`, pl: `Na jakie nazwisko?`},{who: `you`, es: `A nombre de Kowalski.`, pl: `Na nazwisko Kowalski.`},{who: `them`, es: `Sí, aquí está su reserva para dos noches.`, pl: `Tak, tutaj jest pana/pani rezerwacja na dwie noce.`},{who: `you`, es: `Perfecto, quisiera registrarme.`, pl: `Świetnie, chciałbym/chciałabym się zameldować.`},{who: `them`, es: `Necesito su pasaporte, por favor.`, pl: `Potrzebuję pana/pani paszportu, proszę.`},{who: `you`, es: `Aquí está mi pasaporte.`, pl: `Oto mój paszport.`},{who: `them`, es: `Su habitación es la número cinco.`, pl: `Pana/Pani pokój to numer pięć.`},{who: `you`, es: `¿El desayuno está incluido?`, pl: `Czy śniadanie jest wliczone?`},{who: `them`, es: `Sí, y el ascensor está a la derecha.`, pl: `Tak, a winda jest po prawej.`},{who: `you`, es: `Muchas gracias.`, pl: `Bardzo dziękuję.`}]},{id: 3, title: `Pytanie o drogę do muzeum`, scene: `Spacerujesz po centrum Walencji i chcesz znaleźć muzeum. Zatrzymujesz lokalną osobę i prosisz o proste wskazówki.`, lines: [{who: `you`, es: `Perdón, ¿dónde está el museo?`, pl: `Przepraszam, gdzie jest muzeum?`},{who: `them`, es: `Está cerca, a cinco minutos.`, pl: `Jest blisko, pięć minut stąd.`},{who: `you`, es: `¿Voy recto?`, pl: `Mam iść prosto?`},{who: `them`, es: `Sí, siga recto por esta calle.`, pl: `Tak, proszę iść prosto tą ulicą.`},{who: `you`, es: `¿Y después?`, pl: `A potem?`},{who: `them`, es: `Después gire a la izquierda en la plaza.`, pl: `Potem proszę skręcić w lewo na placu.`},{who: `you`, es: `¿El museo está en la plaza?`, pl: `Czy muzeum jest na placu?`},{who: `them`, es: `No, está después de la iglesia.`, pl: `Nie, jest za kościołem.`},{who: `you`, es: `Perfecto, muchas gracias.`, pl: `Świetnie, bardzo dziękuję.`},{who: `them`, es: `De nada.`, pl: `Nie ma za co.`},{who: `you`, es: `Que tenga buen día.`, pl: `Miłego dnia.`},{who: `them`, es: `Igualmente.`, pl: `Nawzajem.`}]},{id: 4, title: `Kolacja w restauracji`, scene: `Jesteś w restauracji w Sewilli i chcesz zamówić danie bez owoców morza. Pytasz kelnera o rekomendację i deser.`, lines: [{who: `them`, es: `Buenas noches, ¿tiene reserva?`, pl: `Dobry wieczór, czy ma pan/pani rezerwację?`},{who: `you`, es: `Sí, tengo una reserva para dos personas.`, pl: `Tak, mam rezerwację dla dwóch osób.`},{who: `them`, es: `Perfecto, esta es su mesa.`, pl: `Świetnie, to jest państwa stolik.`},{who: `you`, es: `Gracias, quisiera el menú.`, pl: `Dziękuję, poproszę menu.`},{who: `them`, es: `Aquí tiene. ¿Desea beber algo?`, pl: `Proszę bardzo. Czy chce pan/pani coś do picia?`},{who: `you`, es: `Agua mineral, por favor.`, pl: `Wodę mineralną, proszę.`},{who: `them`, es: `¿Qué desea comer?`, pl: `Co chce pan/pani zjeść?`},{who: `you`, es: `No puedo comer mariscos. ¿Qué recomienda?`, pl: `Nie mogę jeść owoców morza. Co pan/pani poleca?`},{who: `them`, es: `Recomiendo el pollo con arroz.`, pl: `Polecam kurczaka z ryżem.`},{who: `you`, es: `Perfecto, quisiera ese plato.`, pl: `Świetnie, poproszę to danie.`},{who: `them`, es: `Muy bien.`, pl: `Bardzo dobrze.`},{who: `you`, es: `¿Tiene postre también?`, pl: `Czy macie też deser?`}]},{id: 5, title: `Kupowanie biletu na metro`, scene: `Jesteś na stacji metra w Mexico City. Chcesz kupić bilet i upewnić się, że dana linia jedzie do centrum.`, lines: [{who: `them`, es: `Buenas tardes, ¿qué necesita?`, pl: `Dzień dobry, czego pan/pani potrzebuje?`},{who: `you`, es: `Quisiera un boleto de metro, por favor.`, pl: `Poproszę bilet na metro.`},{who: `them`, es: `¿Solo uno?`, pl: `Tylko jeden?`},{who: `you`, es: `Sí, solo uno.`, pl: `Tak, tylko jeden.`},{who: `them`, es: `Son cinco pesos.`, pl: `To pięć pesos.`},{who: `you`, es: `Aquí tiene.`, pl: `Proszę.`},{who: `them`, es: `Gracias, aquí está su boleto.`, pl: `Dziękuję, oto pana/pani bilet.`},{who: `you`, es: `¿Esta línea va al centro?`, pl: `Czy ta linia jedzie do centrum?`},{who: `them`, es: `Sí, pero debe cambiar en la próxima estación.`, pl: `Tak, ale trzeba się przesiąść na następnej stacji.`},{who: `you`, es: `¿Dónde está la parada correcta?`, pl: `Gdzie jest właściwy przystanek?`},{who: `them`, es: `Siga recto y baje las escaleras.`, pl: `Proszę iść prosto i zejść po schodach.`},{who: `you`, es: `Gracias por su ayuda.`, pl: `Dziękuję za pomoc.`}]},{id: 6, title: `Zakupy na targu`, scene: `Jesteś na kolorowym targu w Limie i oglądasz pamiątki. Chcesz zapytać o cenę, kolor i możliwość płatności kartą.`, lines: [{who: `them`, es: `Hola, ¿busca algo especial?`, pl: `Cześć, szuka pan/pani czegoś konkretnego?`},{who: `you`, es: `Hola, solo estoy mirando.`, pl: `Cześć, tylko oglądam.`},{who: `them`, es: `Tenemos bolsos, camisetas y regalos.`, pl: `Mamy torby, koszulki i prezenty.`},{who: `you`, es: `¿Cuánto cuesta esto?`, pl: `Ile to kosztuje?`},{who: `them`, es: `Cuesta veinte soles.`, pl: `Kosztuje dwadzieścia soli.`},{who: `you`, es: `¿Tiene uno azul?`, pl: `Czy ma pan/pani niebieski?`},{who: `them`, es: `Sí, aquí tiene uno azul.`, pl: `Tak, tutaj jest niebieski.`},{who: `you`, es: `Es muy bonito, pero un poco caro.`, pl: `Jest bardzo ładny, ale trochę drogi.`},{who: `them`, es: `Puedo hacer un descuento.`, pl: `Mogę dać zniżkę.`},{who: `you`, es: `Perfecto, lo compro.`, pl: `Świetnie, kupuję.`},{who: `them`, es: `¿Paga en efectivo o con tarjeta?`, pl: `Płaci pan/pani gotówką czy kartą?`},{who: `you`, es: `Pago con tarjeta.`, pl: `Płacę kartą.`}]},{id: 7, title: `W aptece`, scene: `Podczas podróży po Kolumbii boli cię głowa i masz gorączkę. Wchodzisz do apteki i prosisz o pomoc.`, lines: [{who: `them`, es: `Buenas tardes, ¿en qué puedo ayudarle?`, pl: `Dzień dobry, w czym mogę pomóc?`},{who: `you`, es: `Buenas tardes, necesito medicina.`, pl: `Dzień dobry, potrzebuję lekarstwa.`},{who: `them`, es: `¿Qué síntomas tiene?`, pl: `Jakie ma pan/pani objawy?`},{who: `you`, es: `Me duele la cabeza y tengo fiebre.`, pl: `Boli mnie głowa i mam gorączkę.`},{who: `them`, es: `¿Tiene tos también?`, pl: `Czy ma pan/pani też kaszel?`},{who: `you`, es: `No, no tengo tos.`, pl: `Nie, nie mam kaszlu.`},{who: `them`, es: `¿Es alérgico a algún medicamento?`, pl: `Czy jest pan uczulony na jakieś lekarstwo?`},{who: `you`, es: `No, no soy alérgico.`, pl: `Nie, nie jestem uczulony.`},{who: `them`, es: `Tome esto con agua.`, pl: `Proszę wziąć to z wodą.`},{who: `you`, es: `Gracias, ¿cuánto cuesta?`, pl: `Dziękuję, ile to kosztuje?`},{who: `them`, es: `Son ocho mil pesos.`, pl: `To osiem tysięcy pesos.`},{who: `you`, es: `Gracias por su ayuda.`, pl: `Dziękuję za pomoc.`}]},{id: 8, title: `Krótka rozmowa z lokalną osobą`, scene: `Siedzisz w parku w Buenos Aires i zaczynasz rozmowę z lokalną osobą. Chcesz powiedzieć, że jesteś z Polski, jesteś na wakacjach i podoba ci się miasto.`, lines: [{who: `you`, es: `Hola, ¿puedo sentarme aquí?`, pl: `Cześć, czy mogę tu usiąść?`},{who: `them`, es: `Sí, claro.`, pl: `Tak, oczywiście.`},{who: `you`, es: `Gracias, soy de Polonia.`, pl: `Dziękuję, jestem z Polski.`},{who: `them`, es: `Qué interesante, ¿estás de vacaciones?`, pl: `Jak ciekawie, jesteś na wakacjach?`},{who: `you`, es: `Sí, estoy de vacaciones.`, pl: `Tak, jestem na wakacjach.`},{who: `them`, es: `¿Te gusta Buenos Aires?`, pl: `Podoba ci się Buenos Aires?`},{who: `you`, es: `Sí, me gusta mucho esta ciudad.`, pl: `Tak, bardzo podoba mi się to miasto.`},{who: `them`, es: `La comida aquí es muy buena.`, pl: `Jedzenie tutaj jest bardzo dobre.`},{who: `you`, es: `Sí, la comida es excelente.`, pl: `Tak, jedzenie jest doskonałe.`},{who: `them`, es: `¿Qué quieres visitar después?`, pl: `Co chcesz zwiedzić potem?`},{who: `you`, es: `Después quiero ir al museo.`, pl: `Potem chcę iść do muzeum.`},{who: `them`, es: `Perfecto, el museo está cerca.`, pl: `Świetnie, muzeum jest blisko.`}]}];